  1	import {
  2	  FeatureFlagHandler,
  3	  K8sResourceCommon,
  4	  ResourceLink,
  5	  SetFeatureFlag
  6	} from '@openshift-console/dynamic-plugin-sdk';
  7	import {
  8	  Alert,
  9	  AlertActionLink,
 10	  Bullseye,
 11	  EmptyState,
 12	  EmptyStateBody,
 13	  EmptyStateHeader,
 14	  EmptyStateVariant,
 15	  PageSection,
 16	  Spinner
 17	} from '@patternfly/react-core';
 18	import _ from 'lodash';
 19	import * as React from 'react';
 20	import { useTranslation } from 'react-i18next';
 21	import { Config, defaultConfig } from '../model/config';
 22	import { FilterCompare, Filters } from '../model/filters';
 23	import { loadConfig } from '../utils/config';
 24	import { ConfigLoadError } from '../utils/errors';
 25	import { findFilter, getFilterDefinitions } from '../utils/filter-definitions';
 26	import { usePrevious } from '../utils/previous-hook';
 27	import Error from './messages/error';
 28	import NetflowTrafficParent from './netflow-traffic-parent';
 29	
 30	type NetflowTrafficTabProps<R extends K8sResourceCommon = K8sResourceCommon> = {
 31	  match?: {
 32	    params?: {
 33	      ns?: string;
 34	    };
 35	  };
 36	  obj?: R;
 37	  params?: {
 38	    ns?: string;
 39	  };
 40	};
 41	
 42	type RouteProps = K8sResourceCommon & {
 43	  spec: {
 44	    to: {
 45	      kind?: string;
 46	      name?: string;
 47	    };
 48	  };
 49	};
 50	
 51	type HPAProps = K8sResourceCommon & {
 52	  spec: {
 53	    scaleTargetRef: {
 54	      kind?: string;
 55	      name?: string;
 56	    };
 57	  };
 58	};
 59	
 60	export const NetflowTrafficTab: React.FC<NetflowTrafficTabProps> = ({ match, obj, params }) => {
 61	  const { t } = useTranslation('plugin__netobserv-plugin');
 62	
 63	  //default to 800 to allow content to be rendered in tests
 64	  const [containerHeight, setContainerHeight] = React.useState(800);
 65	  const initState = React.useRef<
 66	    Array<'initDone' | 'configLoading' | 'configLoaded' | 'configLoadError' | 'forcedFiltersLoaded'>
 67	  >([]);
 68	  const [config, setConfig] = React.useState<Config>(defaultConfig);
 69	  const [error, setError] = React.useState<ConfigLoadError | undefined>();
 70	  const [forcedFilters, setForcedFilters] = React.useState<Filters>();
 71	  const [gatewayInfo, setGatewayInfo] = React.useState<{ name: string; namespace: string } | undefined>();
 72	  const previous = usePrevious({ obj });
 73	
 74	  React.useEffect(() => {
 75	    // init function will be triggered only once
 76	    if (!initState.current.includes('initDone')) {
 77	      initState.current.push('initDone');
 78	
 79	      // load config only once and track its state
 80	      if (!initState.current.includes('configLoading')) {
 81	        initState.current.push('configLoading');
 82	        loadConfig().then(v => {
 83	          setConfig(v.config);
 84	          initState.current.push('configLoaded');
 85	          if (v.error) {
 86	            initState.current.push('configLoadError');
 87	            setError(v.error);
 88	          }
 89	        });
 90	      }
 91	    }
 92	
 93	    const containers = document.getElementsByClassName('pf-v6-c-tab-content');
 94	    if (containers.length > 0) {
 95	      setContainerHeight(containers[0].clientHeight);
 96	    }
 97	    // eslint-disable-next-line react-hooks/exhaustive-deps
 98	  }, []);
 99	
100	  React.useEffect(() => {
101	    const filterDefinitions = getFilterDefinitions(config.filters, config.columns, t);
102	
103	    if (
104	      !initState.current.includes('configLoaded') ||
105	      _.isEmpty(filterDefinitions) ||
106	      (initState.current.includes('forcedFiltersLoaded') &&
107	        obj?.kind === previous?.obj?.kind &&
108	        obj?.metadata?.name === previous?.obj?.metadata?.name &&
109	        obj?.metadata?.namespace === previous?.obj?.metadata?.namespace)
110	    ) {
111	      return;
112	    }
113	
114	    initState.current.push('forcedFiltersLoaded');
115	
116	    // Reset gateway info by default
117	    setGatewayInfo(undefined);
118	
119	    switch (obj?.kind) {
120	      case 'Pod':
121	      case 'Deployment':
122	      case 'StatefulSet':
123	      case 'DaemonSet':
124	      case 'Job':
125	      case 'CronJob': {
126	        // Check for Gateway label on Deployments
127	        if (obj.kind === 'Deployment') {
128	          const gatewayLabel = obj.metadata?.labels?.['gateway.networking.k8s.io/gateway-name'];
129	          if (gatewayLabel) {
130	            setGatewayInfo({
131	              name: gatewayLabel,
132	              namespace: obj.metadata!.namespace!
133	            });
134	          }
135	        }
136	
137	        setForcedFilters({
138	          list: [
139	            {
140	              def: findFilter(filterDefinitions, 'src_resource')!,
141	              compare: FilterCompare.equal,
142	              values: [{ v: `${obj.kind}.${obj.metadata!.namespace}.${obj.metadata!.name}` }]
143	            }
144	          ],
145	          match: 'bidirectional'
146	        });
147	        break;
148	      }
149	      case 'Service':
150	        // NOTE: Services are always on the destination side
151	        setForcedFilters({
152	          list: [
153	            {
154	              def: findFilter(filterDefinitions, 'dst_resource')!,
155	              compare: FilterCompare.equal,
156	              values: [{ v: `${obj.kind}.${obj.metadata!.namespace}.${obj.metadata!.name}` }]
157	            }
158	          ],
159	          match: 'all'
160	        });
161	        break;
162	      case 'Gateway':
163	        // NOTE: Gateways can be both ingress (receive traffic) and egress (send traffic)
164	        setForcedFilters({
165	          list: [
166	            {
167	              def: findFilter(filterDefinitions, 'src_resource')!,
168	              compare: FilterCompare.equal,
169	              values: [{ v: `${obj.kind}.${obj.metadata!.namespace}.${obj.metadata!.name}` }]
170	            }
171	          ],
172	          match: 'bidirectional'
173	        });
174	        break;
175	      case 'Route':
176	        const route = obj as RouteProps;
177	        setForcedFilters({
178	          list: [
179	            {
180	              def: findFilter(filterDefinitions, 'dst_resource')!,
181	              compare: FilterCompare.equal,
182	              values: [{ v: `${route.spec.to!.kind}.${route.metadata!.namespace}.${route.spec.to!.name}` }]
183	            }
184	          ],
185	          match: 'all'
186	        });
187	        break;
188	      case 'Namespace':
189	        setForcedFilters({
190	          list: [
191	            {
192	              def: findFilter(filterDefinitions, 'src_namespace')!,
193	              compare: FilterCompare.equal,
194	              values: [{ v: obj!.metadata!.name as string }]
195	            }
196	          ],
197	          match: 'bidirectional'
198	        });
199	        break;
200	      case 'Node':
201	        setForcedFilters({
202	          list: [
203	            {
204	              def: findFilter(filterDefinitions, 'src_host_name')!,
205	              compare: FilterCompare.equal,
206	              values: [{ v: obj!.metadata!.name as string }]
207	            }
208	          ],
209	          match: 'bidirectional'
210	        });
211	        break;
212	      case 'ReplicaSet':
213	        setForcedFilters({
214	          list: [
215	            {
216	              def: findFilter(filterDefinitions, 'src_resource')!,
217	              compare: FilterCompare.equal,
218	              values: obj.metadata!.ownerReferences!.map(ownerRef => {
219	                return { v: `${ownerRef.kind}.${obj.metadata!.namespace}.${ownerRef.name}` };
220	              })
221	            }
222	          ],
223	          match: 'bidirectional'
224	        });
225	        break;
226	      case 'HorizontalPodAutoscaler':
227	        const hpa = obj as HPAProps;
228	        setForcedFilters({
229	          list: [
230	            {
231	              def: findFilter(filterDefinitions, 'src_resource')!,
232	              compare: FilterCompare.equal,
233	              values: [
234	                { v: `${hpa.spec.scaleTargetRef.kind}.${hpa.metadata!.namespace}.${hpa.spec.scaleTargetRef.name}` }
235	              ]
236	            }
237	          ],
238	          match: 'bidirectional'
239	        });
240	        break;
241	    }
242	  }, [config, obj, previous, t]);
243	
244	  if (error) {
245	    return <Error title={t('Unable to get config')} error={error} />;
246	  } else if (!initState.current.includes('forcedFiltersLoaded')) {
247	    return (
248	      <Bullseye data-test="loading-tab">
249	        <Spinner size="xl" />
250	      </Bullseye>
251	    );
252	  } else if (forcedFilters) {
253	    return (
254	      <div className="netobserv-tab-container" style={{ height: containerHeight - 190 }}>
255	        {gatewayInfo && (
256	          <Alert
257	            variant="info"
258	            isInline
259	            title={t('This Deployment is managed by a Gateway')}
260	            style={{ margin: '0 1rem 1rem 1rem' }}
261	            actionLinks={
262	              <AlertActionLink>
263	                <ResourceLink
264	                  inline={true}
265	                  groupVersionKind={{
266	                    group: 'gateway.networking.k8s.io',
267	                    version: 'v1',
268	                    kind: 'Gateway'
269	                  }}
270	                  name={gatewayInfo.name}
271	                  namespace={gatewayInfo.namespace}
272	                />
273	              </AlertActionLink>
274	            }
275	          >
276	            {t('To view the Gateway traffic, visit the Gateway resource page.')}
277	          </Alert>
278	        )}
279	        <NetflowTrafficParent
280	          forcedNamespace={params?.ns || match?.params?.ns}
281	          forcedFilters={forcedFilters}
282	          isTab={true}
283	          hideTitle={true}
284	          parentConfig={config}
285	        />
286	      </div>
287	    );
288	  } else {
289	    return (
290	      <PageSection id="pageSection" data-test="tab-page-section">
291	        <EmptyState data-test="error-state" variant={EmptyStateVariant.sm}>
292	          <EmptyStateHeader titleText={t('Kind not managed')} headingLevel="h2" />
293	          <EmptyStateBody>{obj?.kind}</EmptyStateBody>
294	        </EmptyState>
295	      </PageSection>
296	    );
297	  }
298	};
299	
300	export const featureFlagHandler: FeatureFlagHandler = (setFeatureFlag: SetFeatureFlag) => {
301	  loadConfig().then(({ config }) => {
302	    if (config) {
303	      const lokiEnabled = config.dataSources.some(ds => ds === 'loki');
304	      setFeatureFlag('NETOBSERV_LOKI_ENABLED', lokiEnabled);
305	    }
306	  });
307	};
308	
309	export default NetflowTrafficTab;

